import{_ as a,c as s,b as n,o as i}from"./app-RrIk7Rat.js";const t={};function o(c,e){return i(),s("div",null,e[0]||(e[0]=[n(`<h1 id="iiif-tools-src-tools-iiif-js" tabindex="-1"><a class="header-anchor" href="#iiif-tools-src-tools-iiif-js"><span>IIIF Tools (<code>src/tools/iiif.js</code>)</span></a></h1><p>Helper functions for converting <strong>IIIF manifests</strong> into MEI XML documents, validating manifests, and extracting pages.</p><hr><h2 id="addpage-canvas-canvases-dimension-n-file-meisurfacetemplate-hasitems" tabindex="-1"><a class="header-anchor" href="#addpage-canvas-canvases-dimension-n-file-meisurfacetemplate-hasitems"><span><code>addPage(canvas, canvases, dimension, n, file, meiSurfaceTemplate, hasItems)</code></span></a></h2><p>Adds a page (<code>&lt;surface&gt;</code>) to the MEI file from a IIIF canvas.</p><p><strong>Parameters:</strong></p><ul><li><code>canvas {Object}</code> — IIIF canvas object</li><li><code>canvases {Array}</code> — Array of all canvases (for dimension lookup)</li><li><code>dimension {Array}</code> — <code>[width, height]</code> for the image</li><li><code>n {number}</code> — Page number (1-based)</li><li><code>file {Document}</code> — The MEI XML document to modify</li><li><code>meiSurfaceTemplate {Document}</code> — MEI surface template XML</li><li><code>hasItems {boolean}</code> — <code>true</code> if IIIF Presentation 3 (items), <code>false</code> if Presentation 2 (images)</li></ul><p><strong>Behavior:</strong></p><ul><li>Extracts the label and dimensions of the canvas.</li><li>Determines the <code>info.json</code> URI based on IIIF version.</li><li>Generates unique IDs for <code>&lt;surface&gt;</code> and <code>&lt;graphic&gt;</code>.</li><li>Clones the surface template, sets attributes, and appends it to the MEI <code>&lt;facsimile&gt;</code>.</li></ul><hr><h2 id="iiifmanifest2mei-json-url-parser-state" tabindex="-1"><a class="header-anchor" href="#iiifmanifest2mei-json-url-parser-state"><span><code>iiifManifest2mei(json, url, parser, state)</code></span></a></h2><p>Converts a IIIF manifest JSON object into an MEI XML document.</p><p><strong>Parameters:</strong></p><ul><li><code>json {Object}</code> — IIIF manifest JSON</li><li><code>url {string}</code> — Manifest URL</li><li><code>parser {DOMParser}</code> — XML parser instance</li><li><code>state {Object}</code> — Application state (for page dimensions)</li></ul><p><strong>Behavior:</strong></p><ul><li>Loads MEI file and surface templates asynchronously.</li><li>Sets up MEI metadata (title, source, date, etc.) from the IIIF manifest.</li><li>Attempts to extract <strong>shelfmark</strong> and <strong>composer</strong> from IIIF metadata.</li><li>Iterates over canvases (Presentation 2) or items (Presentation 3) and adds each as a surface/page using <code>addPage</code>.</li></ul><p><strong>Returns:</strong></p><ul><li><code>Promise&lt;Document&gt;</code> — Resolves to the generated MEI XML document.</li></ul><hr><h2 id="checkiiifmanifest-json" tabindex="-1"><a class="header-anchor" href="#checkiiifmanifest-json"><span><code>checkIiifManifest(json)</code></span></a></h2><p>Checks if a given JSON object is a valid IIIF manifest (Presentation 2 or 3).</p><p><strong>Parameters:</strong></p><ul><li><code>json {Object}</code> — IIIF manifest JSON</li></ul><p><strong>Returns:</strong></p><ul><li><code>{boolean}</code> — <code>true</code> if the manifest is valid, otherwise <code>false</code>.</li></ul><p><strong>Validation logic:</strong></p><ul><li>Verifies IIIF context (<code>@context</code>)</li><li>Checks manifest type (<code>sc:Manifest</code>)</li><li>Ensures an ID (<code>@id</code>) is present</li><li>Confirms presence of <code>sequences</code> (IIIF v2) or <code>items</code> (IIIF v3)</li></ul><hr><h2 id="getpagearray-mei" tabindex="-1"><a class="header-anchor" href="#getpagearray-mei"><span><code>getPageArray(mei)</code></span></a></h2><p>Extracts an array of page objects from an MEI XML document.</p><p><strong>Parameters:</strong></p><ul><li><code>mei {Document}</code> — MEI XML document</li></ul><p><strong>Returns:</strong></p><ul><li><code>{Array}</code> — Array of page objects with: <ul><li><code>uri</code> — Image target URI</li><li><code>id</code> — MEI surface ID</li><li><code>n</code> — Page number</li><li><code>width</code>, <code>height</code> — Dimensions</li><li><code>hasSvg</code> — Whether the surface has an embedded SVG</li><li><code>hasZones</code> — Whether the surface contains zones</li></ul></li></ul><hr><h2 id="example-usage" tabindex="-1"><a class="header-anchor" href="#example-usage"><span>Example Usage</span></a></h2><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> iiifManifest2mei<span class="token punctuation">,</span> checkIiifManifest<span class="token punctuation">,</span> getPageArray <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/tools/iiif.js&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Validate a manifest</span></span>
<span class="line"><span class="token keyword">const</span> isValid <span class="token operator">=</span> <span class="token function">checkIiifManifest</span><span class="token punctuation">(</span>manifestJson<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Convert IIIF manifest to MEI</span></span>
<span class="line"><span class="token keyword">const</span> meiDoc <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">iiifManifest2mei</span><span class="token punctuation">(</span>manifestJson<span class="token punctuation">,</span> manifestUrl<span class="token punctuation">,</span> parser<span class="token punctuation">,</span> state<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Extract page data</span></span>
<span class="line"><span class="token keyword">const</span> pages <span class="token operator">=</span> <span class="token function">getPageArray</span><span class="token punctuation">(</span>meiDoc<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,37)]))}const r=a(t,[["render",o]]),d=JSON.parse('{"path":"/technical/iiif.html","title":"IIIF Tools (src/tools/iiif.js)","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756281088000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":3,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"55e94568e1d1bbbd7ef2f19b2073c47d9d521acb","time":1756281088000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Adding a new content"},{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"},{"hash":"addcf634062a696867cd389eb76f27f467f4a69a","time":1747234892000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Correcting the impits based on the pr comments"}]},"filePathRelative":"technical/iiif.md"}');export{r as comp,d as data};
